import React, { useState, useEffect } from 'react';
import { useAuth } from '../context/AuthContext';
import { useLang } from '../context/LangContext';
import T from '../data/translations';
import { getAdminStats, getPendingUsers, getPendingListings, getActiveTransactions, approveUser, rejectUser, approveListing, rejectListing, scheduleVisit } from '../utils/mockService';
import { RoleBadge, StatusBadge } from '../components/Badge';
import Toast from '../components/Toast';

function StatCard({ label, value, color, bg, icon }) {
  return (
    <div className="admin-stat gc">
      <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', marginBottom: 6 }}>
        <div style={{ fontSize: 11, fontWeight: 600, color: 'var(--text2)', textTransform: 'uppercase', letterSpacing: '.5px' }}>{label}</div>
        <div style={{ width: 34, height: 34, borderRadius: 10, background: bg, color, display: 'flex', alignItems: 'center', justifyContent: 'center' }}>{icon}</div>
      </div>
      <div style={{ fontSize: 28, fontWeight: 900, color: 'var(--text)', letterSpacing: '-1px' }}>{value}</div>
    </div>
  );
}

export default function AdminPage({ navigate }) {
  const { user } = useAuth();
  const { lang } = useLang();
  const t = T[lang];

  const [tab, setTab] = useState('accounts');
  const [stats, setStats] = useState({ pendingUsers: 0, pendingListings: 0, totalUsers: 0, activeTransactions: 0 });
  const [pendingUsers, setPendingUsers] = useState([]);
  const [pendingListings, setPendingListings] = useState([]);
  const [transactions, setTransactions] = useState([]);
  const [toast, setToast] = useState(null);

  const reload = () => {
    setStats(getAdminStats());
    setPendingUsers(getPendingUsers());
    setPendingListings(getPendingListings());
    setTransactions(getActiveTransactions());
  };

  useEffect(() => { reload(); }, []);

  if (!user || user.role !== 'admin') {
    return (
      <div className="pg pi" style={{ textAlign: 'center', paddingTop: 60 }}>
        <h2 style={{ marginBottom: 12 }}>{t.errors.adminOnly}</h2>
        <button className="btn-p" onClick={() => navigate('login')}>{t.btn.login}</button>
      </div>
    );
  }

  const handleApproveUser = (id) => {
    approveUser(id);
    reload();
    setToast({ message: t.success.userApproved, type: 'success' });
  };

  const handleRejectUser = (id) => {
    rejectUser(id);
    reload();
    setToast({ message: t.success.userRejected, type: 'info' });
  };

  const handleScheduleUser = (id) => {
    scheduleVisit(id, 'user');
    setToast({ message: t.success.visitScheduled, type: 'info' });
  };

  const handleApproveListing = (id) => {
    approveListing(id);
    reload();
    setToast({ message: t.success.listingApproved, type: 'success' });
  };

  const handleRejectListing = (id) => {
    rejectListing(id);
    reload();
    setToast({ message: t.success.listingRejected, type: 'info' });
  };

  const handleScheduleListing = (id) => {
    scheduleVisit(id, 'listing');
    setToast({ message: t.success.visitScheduled, type: 'info' });
  };

  const tabs = [
    { key: 'accounts', label: t.admin.accounts, count: stats.pendingUsers },
    { key: 'listings', label: t.admin.listings, count: stats.pendingListings },
    { key: 'transactions', label: t.admin.transactions, count: stats.activeTransactions },
  ];

  return (
    <div className="pg pi">
      {toast && <Toast message={toast.message} type={toast.type} onClose={() => setToast(null)} />}

      <div className="pg-h">
        <div style={{ display: 'flex', alignItems: 'center', gap: 12, marginBottom: 6 }}>
          <div style={{ width: 44, height: 44, borderRadius: 12, background: 'linear-gradient(135deg,#16a34a,#0ea5e9)', display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
            <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="#fff" strokeWidth="2"><path d="M12 22s8-4 8-10V5l-8-3-8 3v7c0 6 8 10 8 10z" /></svg>
          </div>
          <h1 className="pg-t">{t.pages.admin}</h1>
        </div>
        <p style={{ fontSize: 14, color: 'var(--text2)' }}>
          {lang === 'en' ? `Welcome, ${user.name}. Manage platform users, listings, and transactions.` : `Murakaza, ${user.name}. Genzura abakoresheje, amatangazo, n'ubucuruzi.`}
        </p>
      </div>

      {/* Stats */}
      <div className="admin-stats">
        <StatCard label={t.dash.pendingUsers} value={stats.pendingUsers} color="#f59e0b" bg="#fef3c7"
          icon={<svg width="15" height="15" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><path d="M19 21v-2a4 4 0 0 0-4-4H9a4 4 0 0 0-4 4v2" /><circle cx="12" cy="7" r="4" /></svg>} />
        <StatCard label={t.dash.pendingListings} value={stats.pendingListings} color="#ef4444" bg="#fee2e2"
          icon={<svg width="15" height="15" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><path d="M6 2L3 6v14a2 2 0 0 0 2 2h14a2 2 0 0 0 2-2V6l-3-4z" /><line x1="3" y1="6" x2="21" y2="6" /><path d="M16 10a4 4 0 0 1-8 0" /></svg>} />
        <StatCard label={t.dash.activeTx} value={stats.activeTransactions} color="#0ea5e9" bg="#e0f2fe"
          icon={<svg width="15" height="15" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><rect x="1" y="3" width="15" height="13" /><polygon points="16 8 20 8 23 11 23 16 16 16 16 8" /><circle cx="5.5" cy="18.5" r="2.5" /><circle cx="18.5" cy="18.5" r="2.5" /></svg>} />
        <StatCard label={t.dash.totalUsers} value={stats.totalUsers} color="#7c3aed" bg="#ede9fe"
          icon={<svg width="15" height="15" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><path d="M17 21v-2a4 4 0 0 0-4-4H5a4 4 0 0 0-4 4v2" /><circle cx="9" cy="7" r="4" /><path d="M23 21v-2a4 4 0 0 0-3-3.87" /><path d="M16 3.13a4 4 0 0 1 0 7.75" /></svg>} />
      </div>

      {/* Tabs */}
      <div className="admin-tabs">
        {tabs.map(tab2 => (
          <button key={tab2.key} className={`at${tab === tab2.key ? ' att' : ''}`} onClick={() => setTab(tab2.key)}>
            {tab2.label}
            {tab2.count > 0 && (
              <span style={{
                marginLeft: 6, background: tab === tab2.key ? 'rgba(255,255,255,.2)' : 'var(--red)',
                color: tab === tab2.key ? '#fff' : '#fff',
                borderRadius: 100, padding: '1px 7px', fontSize: 11, fontWeight: 700,
              }}>
                {tab2.count}
              </span>
            )}
          </button>
        ))}
      </div>

      {/* Tab 1: Account Requests */}
      {tab === 'accounts' && (
        <div>
          {pendingUsers.length === 0 ? (
            <div className="gc" style={{ padding: 40, textAlign: 'center', color: 'var(--text2)' }}>
              <svg width="40" height="40" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.5" style={{ margin: '0 auto 12px', display: 'block', opacity: 0.3 }}>
                <polyline points="20 6 9 17 4 12" />
              </svg>
              {t.admin.noRequests}
            </div>
          ) : (
            <div style={{ display: 'flex', flexDirection: 'column', gap: 12 }}>
              {pendingUsers.map(u => (
                <div key={u.id} className="gc" style={{ padding: '18px 20px' }}>
                  <div style={{ display: 'flex', alignItems: 'center', gap: 14, flexWrap: 'wrap' }}>
                    <div style={{ width: 44, height: 44, borderRadius: '50%', background: 'linear-gradient(135deg,var(--green),var(--blue))', color: '#fff', fontSize: 14, fontWeight: 700, display: 'flex', alignItems: 'center', justifyContent: 'center', flexShrink: 0 }}>
                      {u.avatar?.slice(0, 2)}
                    </div>
                    <div style={{ flex: 1, minWidth: 180 }}>
                      <div style={{ fontWeight: 700, fontSize: 15 }}>{u.name}</div>
                      <div style={{ fontSize: 12, color: 'var(--text2)', marginTop: 2 }}>{u.email}</div>
                      <div style={{ fontSize: 12, color: 'var(--text2)' }}>{u.sector}</div>
                      {u.spec && <div style={{ fontSize: 12, color: 'var(--text2)' }}>{lang === 'en' ? 'Specialization:' : 'Inzobere:'} {u.spec}</div>}
                      {u.company && <div style={{ fontSize: 12, color: 'var(--text2)' }}>{lang === 'en' ? 'Company:' : 'Ikigo:'} {u.company}</div>}
                    </div>
                    <div style={{ display: 'flex', flexDirection: 'column', gap: 6, alignItems: 'flex-end' }}>
                      <RoleBadge role={u.role} />
                      {u.date && <span style={{ fontSize: 11, color: 'var(--text3)' }}>{u.date}</span>}
                    </div>
                  </div>
                  <div style={{ display: 'flex', gap: 8, marginTop: 14, flexWrap: 'wrap' }}>
                    <button className="btn-acc" style={{ flex: 1, minWidth: 100 }} onClick={() => handleApproveUser(u.id)}>
                      <svg width="13" height="13" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5"><polyline points="20 6 9 17 4 12" /></svg>
                      {t.btn.approve}
                    </button>
                    <button className="btn-ctr" style={{ flex: 1, minWidth: 100 }} onClick={() => handleScheduleUser(u.id)}>
                      <svg width="13" height="13" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><rect x="3" y="4" width="18" height="18" rx="2" ry="2" /><line x1="16" y1="2" x2="16" y2="6" /><line x1="8" y1="2" x2="8" y2="6" /><line x1="3" y1="10" x2="21" y2="10" /></svg>
                      {t.btn.scheduleVisit}
                    </button>
                    <button className="btn-dec" style={{ flex: 1, minWidth: 100 }} onClick={() => handleRejectUser(u.id)}>
                      <svg width="13" height="13" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5"><line x1="18" y1="6" x2="6" y2="18" /><line x1="6" y1="6" x2="18" y2="18" /></svg>
                      {t.btn.reject}
                    </button>
                  </div>
                </div>
              ))}
            </div>
          )}
        </div>
      )}

      {/* Tab 2: Listing Review */}
      {tab === 'listings' && (
        <div>
          {pendingListings.length === 0 ? (
            <div className="gc" style={{ padding: 40, textAlign: 'center', color: 'var(--text2)' }}>
              <svg width="40" height="40" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.5" style={{ margin: '0 auto 12px', display: 'block', opacity: 0.3 }}>
                <polyline points="20 6 9 17 4 12" />
              </svg>
              {t.admin.noListings}
            </div>
          ) : (
            <div style={{ display: 'flex', flexDirection: 'column', gap: 12 }}>
              {pendingListings.map(l => (
                <div key={l.id} className="gc" style={{ padding: '18px 20px' }}>
                  <div style={{ display: 'flex', gap: 14, alignItems: 'flex-start', flexWrap: 'wrap' }}>
                    <img src={l.image} alt={l.title} style={{ width: 80, height: 60, borderRadius: 10, objectFit: 'cover', flexShrink: 0 }} />
                    <div style={{ flex: 1, minWidth: 180 }}>
                      <div style={{ fontWeight: 700, fontSize: 14, marginBottom: 4 }}>{l.title}</div>
                      <div style={{ fontSize: 12, color: 'var(--text2)', marginBottom: 4 }}>{l.description?.slice(0, 80)}...</div>
                      <div style={{ display: 'flex', gap: 8, flexWrap: 'wrap', alignItems: 'center' }}>
                        <span style={{ background: 'var(--bg)', borderRadius: 100, padding: '2px 9px', fontSize: 10, fontWeight: 700, textTransform: 'capitalize', color: 'var(--text2)' }}>{l.material}</span>
                        <span style={{ fontSize: 12, color: 'var(--green)', fontWeight: 700 }}>{l.price?.toLocaleString()} RWF</span>
                        <span style={{ fontSize: 11, color: 'var(--text3)' }}>{l.sector}</span>
                        <span style={{ fontSize: 11, color: 'var(--text3)' }}>{l.date}</span>
                      </div>
                    </div>
                  </div>
                  <div style={{ display: 'flex', gap: 8, marginTop: 14, flexWrap: 'wrap' }}>
                    <button className="btn-acc" style={{ flex: 1, minWidth: 100 }} onClick={() => handleApproveListing(l.id)}>
                      <svg width="13" height="13" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5"><polyline points="20 6 9 17 4 12" /></svg>
                      {t.btn.approve}
                    </button>
                    <button className="btn-ctr" style={{ flex: 1, minWidth: 100 }} onClick={() => handleScheduleListing(l.id)}>
                      <svg width="13" height="13" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><rect x="3" y="4" width="18" height="18" rx="2" ry="2" /><line x1="16" y1="2" x2="16" y2="6" /><line x1="8" y1="2" x2="8" y2="6" /><line x1="3" y1="10" x2="21" y2="10" /></svg>
                      {t.btn.scheduleVisit}
                    </button>
                    <button className="btn-dec" style={{ flex: 1, minWidth: 100 }} onClick={() => handleRejectListing(l.id)}>
                      <svg width="13" height="13" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5"><line x1="18" y1="6" x2="6" y2="18" /><line x1="6" y1="6" x2="18" y2="18" /></svg>
                      {t.btn.reject}
                    </button>
                  </div>
                </div>
              ))}
            </div>
          )}
        </div>
      )}

      {/* Tab 3: Transactions */}
      {tab === 'transactions' && (
        <div>
          {transactions.length === 0 ? (
            <div className="gc" style={{ padding: 40, textAlign: 'center', color: 'var(--text2)' }}>
              <svg width="40" height="40" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.5" style={{ margin: '0 auto 12px', display: 'block', opacity: 0.3 }}>
                <rect x="1" y="3" width="15" height="13" /><polygon points="16 8 20 8 23 11 23 16 16 16 16 8" />
              </svg>
              {t.admin.noTransactions}
            </div>
          ) : (
            <div style={{ display: 'flex', flexDirection: 'column', gap: 10 }}>
              {transactions.map(tx => (
                <div key={tx.id} className="gc" style={{ padding: '16px 20px' }}>
                  <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', gap: 12, flexWrap: 'wrap' }}>
                    <div>
                      <div style={{ fontWeight: 700, fontSize: 14, marginBottom: 4 }}>{tx.listingTitle}</div>
                      <div style={{ fontSize: 12, color: 'var(--text2)' }}>
                        {lang === 'en' ? 'Buyer:' : 'Umugura:'} <strong>{tx.buyerName}</strong>
                        {' · '}
                        {lang === 'en' ? 'Seller:' : 'Umucuruzi:'} <strong>{tx.sellerName}</strong>
                      </div>
                      <div style={{ fontSize: 12, color: 'var(--text2)', marginTop: 2 }}>{tx.date}</div>
                    </div>
                    <div style={{ textAlign: 'right', flexShrink: 0 }}>
                      <div style={{ fontSize: 16, fontWeight: 800, color: 'var(--green)' }}>{tx.amount?.toLocaleString()} RWF</div>
                      <StatusBadge status={tx.txStatus || 'accepted'} />
                    </div>
                  </div>
                </div>
              ))}
            </div>
          )}
        </div>
      )}
    </div>
  );
}
